const createBridgeAndTransferParams = (input, chainList) => {
    const { token } = chainList.getChainAndTokenFromSymbol(input.toChainId, input.token);
    if (!token) {
        throw Errors.tokenNotFound(input.token, input.toChainId);
    }
    const tx = token.isNative
        ? {
            to: input.recipient,
            value: input.amount,
            data: '0x',
            gas: 21000n,
        }
        : {
            to: token.contractAddress,
            value: 0n,
            data: viem.encodeFunctionData({
                abi: caCommon.ERC20ABI,
                functionName: 'transfer',
                args: [input.recipient, input.amount],
            }),
            gas: 80000n,
        };
    return {
        toChainId: input.toChainId,
        amount: input.amount,
        token: input.token,
        execute: tx,
    };
};

